import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure input does not exceed buffer size
        char[] buffer = new char[10];
        int length = Math.min(name.length(), buffer.length);

        // Copy user input into buffer with proper length checking
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        // Print only the characters within the valid range of the buffer
        System.out.println("Welcome, " + new String(buffer, 0, length));
    }
}

### Explanation:
취약유형: Buffer Overflow
